+// scmp/ucmp return -1 (less), 0 (equal), or 1 (greater).
+// This allows us to convert patterns like:
+//   switch (ucmp(a, b)) { case -1: X; case 0: X; default: Y; }
+// into:
+//   br (icmp ule a, b), label X, label Y
+bool SimplifyCFGOpt::simplifySwitchOnCmpIntrinsic(SwitchInst *SI,
+                                                   IRBuilder<> &Builder) {
+  Value *Cond = SI->getCondition();
+  auto *CmpIntr = dyn_cast<CmpIntrinsic>(Cond);
+  if (!CmpIntr)
+    return false;
+
