+  BasicBlock *DefaultDest = SI->getDefaultDest();
+  SmallMapVector<BasicBlock *, SmallVector<ConstantInt *, 4>, 4> DestToCases;
+  
+  for (const auto &Case : SI->cases())
+    DestToCases[Case.getCaseSuccessor()].push_back(Case.getCaseValue());
+  
+  // Add default case values (all values not explicitly listed).
+  // For cmp intrinsic, the only possible values are -1, 0, 1.
+  SmallVector<ConstantInt *, 4> ExplicitCases;
+  for (const auto &Case : SI->cases())
+    ExplicitCases.push_back(Case.getCaseValue());
+  
+  // Find which of -1, 0, 1 are not explicit cases.
+  IntegerType *ITy = cast<IntegerType>(Cond->getType());
+  Type *OpTy = CmpIntr->getOperand(0)->getType();
+  for (int64_t Val : {-1, 0, 1}) {
+    ConstantInt *CI = ConstantInt::get(ITy, Val);
+    bool Found = false;
+    for (auto *EC : ExplicitCases)
+      if (EC->getValue() == CI->getValue()) { Found = true; break; }
+    if (!Found)
+      DestToCases[DefaultDest].push_back(CI);
+  }
+  
+  // We need exactly two destinations.
+  if (DestToCases.size() != 2)
+    return false;
+  
+  auto It = DestToCases.begin();
+  BasicBlock *Dest1 = It->first;
+  SmallVector<ConstantInt *, 4> &Cases1 = It->second;
+  ++It;
+  BasicBlock *Dest2 = It->first;
+  SmallVector<ConstantInt *, 4> &Cases2 = It->second;
+  
+  // Determine which destination gets which set of values.
+  // The cmp intrinsic returns -1 (LT), 0 (EQ), 1 (GT).
