  bool Dest2HasLT = false, Dest2HasEQ = false, Dest2HasGT = false;

  auto ClassifyCases = [&](ArrayRef<ConstantInt *> Cases, bool &HasLT, bool &HasEQ, bool &HasGT) {
    for (auto *C : Cases) {
      int64_t Val = C->getSExtValue();
